var maxSumMinProduct = function(nums) {
    const MOD = BigInt(1000000007);
    let max_product = BigInt(0);
    let stk = [];
    let prefix_sum = new BigInt64Array(nums.length + 1);

    for (let i = 0; i < nums.length; i++) {
        prefix_sum[i + 1] = prefix_sum[i] + BigInt(nums[i]);
    }

    for (let i = 0; i < nums.length; i++) {
        while (stk.length > 0 && nums[stk[stk.length - 1]] > nums[i]) {
            let min_val = nums[stk.pop()];
            max_product = BigInt(Math.max(Number(max_product), Number(min_val * (prefix_sum[i] - prefix_sum[stk.length === 0 ? 0 : stk[stk.length - 1] + 1]))));
        }
        stk.push(i);
    }

    while (stk.length > 0) {
        let min_val = nums[stk.pop()];
        max_product = BigInt(Math.max(Number(max_product), Number(min_val * (prefix_sum[nums.length] - prefix_sum[stk.length === 0 ? 0 : stk[stk.length - 1] + 1]))));
    }

    return Number(max_product % MOD);
};
```


    1. Calculate the prefix sums for every element in the input array.
2. Then, we iterate through the input array and maintain a decreasing monotonic stack.
3. If the current element is lower than the top element of the stack, we calculate the maximum min-product for the top element by popping it from the stack.
4. After processing all elements, we calculate the maximum min-product for the remaining elements in the stack.
5. The time complexity is O(n) as we push and pop each element exactly once.

solutionCode.java:
    ```java
import java.util.Stack;

public int maxSumMinProduct(int[] nums) {
    long max_product = 0;
    Stack<Integer> stk = new Stack<>();
    long[] prefix_sum = new long[nums.length + 1];
    final int MOD = 1000000007;

    for (int i = 0; i < nums.length; i++) {
        prefix_sum[i + 1] = prefix_sum[i] + nums[i];
    }

    for (int i = 0; i < nums.length; i++) {
        while (!stk.isEmpty() && nums[stk.peek()] > nums[i]) {
            int min_val = nums[stk.pop()];
            max_product = Math.max(max_product, min_val * (prefix_sum[i] - prefix_sum[stk.isEmpty() ? 0 : stk.peek() + 1]));
        }
        stk.push(i);
    }

    while (!stk.isEmpty()) {
        int min_val = nums[stk.pop()];
        max_product = Math.max(max_product, min_val * (prefix_sum[nums.length] - prefix_sum[stk.isEmpty() ? 0 : stk.peek() + 1]));
    }

    return (int) (max_product % MOD);
}
```


    1. Calculate the prefix sums for every element in the input array.
2. Then, we iterate through the input array and maintain a decreasing monotonic stack.
3. If the current element is lower than the top element of the stack, we calculate the maximum min-product for the top element by popping it from the stack.
4. After processing all elements, we calculate the maximum min-product for the remaining elements in the stack.
5. The time complexity is O(n) as we push and pop each element exactly once.
